   approfondi:{avis_savants:[{savant:"Imam Muhammad Ibn Sirin (رحمه الله) — Règle d'or",savant_ar:"الإمام محمد بن سيرين",epoque:"33-110H · Bassora",type:"jarh",citation_ar:"إنَّ هذا العلمَ دينٌ، فانظُروا عمَّن تأخُذون دينَكم",citation_fr:"Cette science est une religion — regardez de qui vous prenez votre religion. Sa parole s'applique à tous les TikTokers islamiques sans formation.",source:"Introduction du Sahih Muslim"},{savant:"Cheikh Salih Al-Fawzan (حفظه الله) — Sur les prédicateurs non qualifiés",savant_ar:"الشيخ صالح الفوزان",epoque:"Membre Comité des Grands Savants · Riyad",type:"jarh",citation_ar:"لا يجوز لكل أحد أن يتصدر للتعليم والدعوة دون تزكية أهل العلم",citation_fr:"Il n'est pas permis à n'importe qui de se placer en position d'enseignement et de prédication sans la recommandation des gens de science.",source:"alfawzan.af.org.sa — Fatawa sur les prédicateurs"},{savant:"Cheikh Rabi' Al-Madkhali (حفظه الله) — Sur les prêcheurs d'Internet",savant_ar:"الشيخ ربيع المدخلي",epoque:"Savant vivant · Médine",type:"jarh",citation_ar:"من أخذ دينه من الإنترنت فقد يخرج من الإسلام دون أن يشعر",citation_fr:"Celui qui prend sa religion d'Internet risque de sortir de l'Islam sans s'en rendre compte.",source:"rabee.net"},{savant:"Note Ministère de l'Intérieur français — Mai 2025",savant_ar:"وزارة الداخلية الفرنسية",epoque:"Mai 2025 · France",type:"jarh",citation_ar:"من الملفات الإسلامية المقلقة على تيك توك في فرنسا",citation_fr:"Identifié parmi les profils islamiques préoccupants sur TikTok en France.",source:"Note Minint — mai 2025"}],manhaj:[{point:"Zéro formation islamique — Rédhibitoire",niveau:"rouge",detail:"Aucune formation islamique déclarée ou vérifiable. Aucun savant tuteur. Aucune ijaza. La règle d'Ibn Sirin s'applique : هذا العلم دين فانظروا عمن تأخذون دينكم. Cheikh Al-Fawzan a interdit de prêcher sans tazkiya des savants."},{point:"Discours rigoriste sans science — Dangereux",niveau:"rouge",detail:"Positions sur le halal/haram présentées avec certitude devant 1,2M d'abonnés sans chaîne de transmission ni référence aux savants. La Libre (juillet 2024) documente qu'il réduit l'Islam à une liste d'interdits — ce qui est une déformation de la Shari'a."},{point:"Rapport Minint 2025 — Profil préoccupant",niveau:"orange",detail:"Identifié dans la note confidentielle du Ministère de l'Intérieur français (mai 2025) parmi les influenceurs islamiques préoccupants sur TikTok."}],oeuvres:[],biographie:{naissance:"Inconnu",formation:"Aucune formation islamique documentée.",maitres:"Aucun savant tuteur identifié.",parcours:"Tiktoker islamique francophone. 1,2 million d'abonnés TikTok. Présent depuis 2020. Identifié par les autorités françaises dans la note Minint mai 2025.",affiliations:"Aucune affiliation identifiée."},sources:["https://3ilmchar3i.net","https://binbaz.org.sa","https://rabee.net"]}
